#include <bits/stdc++.h>
using namespace std;
int main(){int n;scanf("%d",&n);vector<int>a(n);for(auto&x:a)scanf("%d",&x);sort(a.begin(),a.end());int q;scanf("%d",&q);string out;while(q--){int x;scanf("%d",&x);long long c=upper_bound(a.begin(),a.end(),x)-lower_bound(a.begin(),a.end(),x);out+=to_string(c);out+=' ';}if(!out.empty())out.pop_back();printf("%s\n",out.c_str());}
